let quality = null;
switch (counterValue) {
  case 2: quality = "slightly damaged"; break;
  case 1: quality = "badly damaged"; break;
  case 0: quality = "destroyed"; break;
}

if (!quality) return;

const actorName = actor?.name ?? "Unknown";
const possessive = actorName.endsWith("s") ? `${actorName}'` : `${actorName}'s`;

const content = `${possessive}'s ${item?.name} is ${quality}.`;
ChatMessage.create({content});
